const inputText = $json.output || $json.text || $json.message || "";

function closeUnmatchedSymbols(text, symbol) {
  const count = (text.match(new RegExp(`\\${symbol}`, 'g')) || []).length;
  // Wenn ungerade Anzahl -> fehlt ein Abschlusszeichen
  if (count % 2 !== 0) {
    return text + symbol;
  }
  return text;
}

// Für alle typischen Markdown-V1-Symbole prüfen:
let safeText = inputText;
['*', '_', '`'].forEach((symbol) => {
  safeText = closeUnmatchedSymbols(safeText, symbol);
});

// Für []-Klammern extra check:
const openBrackets = (safeText.match(/\[/g) || []).length;
const closeBrackets = (safeText.match(/\]/g) || []).length;
if (openBrackets > closeBrackets) {
  safeText += ']';
} else if (closeBrackets > openBrackets) {
  safeText = '[' + safeText;
}

